"use strict";

(function ($) {

    var defaults = {
        direction: "prev",
        mode: "horizontal",
        speed: 1,
        delay: 30,
        pauseOnHover: false,
        onCarouselTickerLoad: function () {}
    };

    $.fn.carouselTicker = function (options) {

        if (this.length === 0) return this;

        if (this.length > 1) {
            return this.each(function () {
                $(this).carouselTicker(options);
            });
        }

        var plugin = {},
            self = this,
            $this = $(this);

        function init() {

            plugin.settings = $.extend({}, defaults, options);
            plugin.intervalPointer = null;
            plugin.directionSwitcher = plugin.settings.direction === "prev" ? -1 : 1;

            plugin.itemsWidth = 0;
            plugin.itemsHeight = 0;

            /* 🔥 FIX START */

            // Target correct row wrapper
            plugin.$list = $this.find(".gs-teca");

            // Direct children only
            plugin.$items = plugin.$list.children(".gs-teca-single");

            // Correct parent for overflow
            plugin.$parent = plugin.$list.parent();

            /* 🔥 FIX END */

            plugin.wrapCls = "carouselTicker__wrap";
            plugin.loaderCls = "carouselTicker__loader";
            plugin.cloneCls = "carouselTicker__clone";

            plugin.touch = "ontouchstart" in document.documentElement;

            plugin.eventTypes = {
                mousedown: plugin.touch ? "touchstart" : "mousedown",
                mousemove: plugin.touch ? "touchmove" : "mousemove",
                mouseup: plugin.touch ? "touchend" : "mouseup"
            };

            plugin.isInitialize = false;
            plugin.isMousemove = false;

            setup();
        }

        function setup() {

            if (!plugin.$list.length || !plugin.$items.length) return;

            if (plugin.settings.mode === "horizontal") {
                calculateWidth();
                if (plugin.itemsWidth > plugin.$parent.width()) {
                    wrap();
                }
            }

            if (plugin.settings.mode === "vertical") {
                plugin.itemsHeight = 0;

                plugin.$items.each(function () {
                    var $item = $(this);
                    if (!$item.hasClass(plugin.cloneCls)) {
                        plugin.itemsHeight += $item.outerHeight(true);
                    }
                });

                if (plugin.itemsHeight > plugin.$parent.height()) {
                    wrap();
                }
            }
        }

        function wrap() {

            if ($this.find("." + plugin.wrapCls).length) return;

            $("<div class='" + plugin.loaderCls + "'></div>").appendTo(plugin.$parent);

            plugin.$list.wrap(
                "<div class='" + plugin.wrapCls + "' style='position:relative;overflow:hidden;'></div>"
            );

            plugin.$items.clone()
                .addClass(plugin.cloneCls)
                .appendTo(plugin.$list);

            plugin.$list.css({ position: "relative" });

            plugin.isInitialize = true;

            plugin.settings.onCarouselTickerLoad();

            run();
        }

        function run() {

            plugin.$parent.find("." + plugin.loaderCls).remove();

            plugin.intervalPointer = setInterval(move, plugin.settings.delay);

            if (plugin.settings.pauseOnHover) {
                plugin.$parent.on("mouseover", stop);
                plugin.$parent.on("mouseleave", resume);
            }
        }

        function move() {

            var prop = plugin.settings.mode === "horizontal" ? "left" : "top";
            var size = plugin.settings.mode === "horizontal"
                ? plugin.itemsWidth
                : plugin.itemsHeight;

            plugin.$list.css(
                prop,
                "+=" + (plugin.directionSwitcher * plugin.settings.speed) + "px"
            );

            if (plugin.settings.direction === "prev" &&
                Math.abs(parseInt(plugin.$list.css(prop))) >= size) {
                plugin.$list.css(prop, 0);
            }

            if (plugin.settings.direction === "next" &&
                parseInt(plugin.$list.css(prop)) >= 0) {
                plugin.$list.css(prop, -size + "px");
            }
        }

        function calculateWidth() {

            plugin.itemsWidth = 0;

            plugin.$items.each(function () {

                var $item = $(this);
                var style = window.getComputedStyle(this);
                var margin =
                    parseFloat(style.marginLeft) +
                    parseFloat(style.marginRight);

                if (!$item.hasClass(plugin.cloneCls)) {
                    plugin.itemsWidth +=
                        this.getBoundingClientRect().width + margin;
                }
            });
        }

        function stop() {
            clearInterval(plugin.intervalPointer);
            plugin.intervalPointer = null;
        }

        function resume() {
            if (!plugin.intervalPointer) {
                plugin.intervalPointer = setInterval(move, plugin.settings.delay);
            }
        }

        self.stop = stop;
        self.run = run;

        if (document.readyState === "loading") {
            $(window).on("load", init);
        } else {
            init();
        }

        return this;
    };

})(jQuery);
